export default function About() {
  return (
    <section id="about" className="relative py-24 lg:py-32">
      <div className="max-w-7xl mx-auto px-6 lg:px-8">
        <div className="grid lg:grid-cols-2 gap-12 lg:gap-20 items-center">
          {/* Image — single photo in device frame */}
          <motion.div
            initial={{ opacity: 0, scale: 0.95 }}
            whileInView={{ opacity: 1, scale: 1 }}
            viewport={{ once: true, margin: '-100px' }}
            transition={{ duration: 0.6 }}
            className="relative flex justify-center"
          >
            {/* Ambient glow behind card */}
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[80%] h-[80%] rounded-full bg-accent-red/20 blur-[80px]" />

            {/* Phone-style frame */}
            <div className="relative w-[280px] sm:w-[320px] rounded-[2.5rem] border-2 border-foreground/10 bg-card overflow-hidden shadow-2xl">
              {/* Notch */}
              <div className="flex justify-center pt-3 pb-2">
                <div className="w-20 h-1.5 rounded-full bg-foreground/10" />
              </div>

              {/* Available badge */}
              <div className="absolute top-12 left-1/2 -translate-x-1/2 z-10">
              <motion.div
                animate={{ y: [0, -8, 0] }}
                transition={{ duration: 3, repeat: Infinity, ease: 'easeInOut' }}
              >
                <div className="flex items-center gap-2 px-4 py-1.5 rounded-full bg-green-500/20 backdrop-blur-sm border border-green-500/30 whitespace-nowrap">
                  <div className="w-2 h-2 flex-shrink-0 rounded-full bg-green-400 animate-pulse" />
                  <span className="text-green-400 text-xs font-medium">Available as freelancer</span>
                </div>
              </motion.div>
              </div>

              {/* Photo placeholder */}
              <div className="aspect-[3/4] bg-muted/30 flex items-center justify-center">
                <img
                  src="/images/PicForWebsite.jpg"
                  alt="Walid El Omari"
                  loading="lazy"
                  className="w-full h-full object-cover"
                />
              </div>

              {/* Tool tags overlaying bottom — desktop only */}
              <div className="absolute bottom-3 inset-x-3 hidden sm:flex flex-wrap gap-1 justify-center">
                {tools.map((tool) => (
                  <span
                    key={tool.label}
                    className="inline-flex items-center gap-1 bg-white/10 backdrop-blur-xl border border-white/20 text-white text-[10px] font-semibold px-2 py-1 rounded-full"
                  >
                    {tool.icon}
                    {tool.label}
                  </span>
                ))}
              </div>

              {/* Tool icons below photo — mobile only */}
              <div className="sm:hidden border-t border-foreground/10 p-3">
                <p className="text-muted-foreground text-[10px] font-semibold uppercase tracking-wider text-center mb-2.5">
                  Tools I work with
                </p>
                <div className="flex flex-wrap justify-center gap-2.5">
                  {tools.map((tool, i) => (
                    <Fragment key={tool.label}>
                      {i === 4 && <div className="basis-full h-0" />}
                      <div
                        title={tool.label}
                        className={cn(
                          'flex items-center justify-center w-9 h-9 rounded-xl bg-foreground/5 border border-foreground/10',
                          tool.label === 'Claude AI' && 'text-[#D97757]',
                          tool.label === 'CapCut' && 'text-white'
                        )}
                      >
                        {tool.icon}
                      </div>
                    </Fragment>
                  ))}
                </div>
              </div>
            </div>
          </motion.div>

          {/* Text Content */}
          <motion.div
            variants={containerVariants}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true, margin: '-100px' }}
            className="space-y-8"
          >
            <motion.h2
              variants={textVariants}
              className="text-4xl md:text-5xl lg:text-6xl font-bold text-foreground leading-tight"
            >
              Content you can
              <br />
              <span className="relative inline-block">
                count on
                <motion.span
                  className="absolute -bottom-2 left-0 w-full h-3 bg-accent-red/60 -z-10"
                  initial={{ scaleX: 0 }}
                  whileInView={{ scaleX: 1 }}
                  viewport={{ once: true }}
                  transition={{ delay: 0.5, duration: 0.3 }}
                />
              </span>
            </motion.h2>

            <motion.p
              variants={textVariants}
              className="text-lg text-muted-foreground leading-relaxed"
            >
              I'm <span className="text-foreground font-medium">Walid El Omari</span>, a
              freelance video editor with over 4 years of hands-on experience. I specialize in{' '}
              <span className="text-foreground font-medium">short-form content</span>,{' '}
              <span className="text-foreground font-medium">UGC editing</span>, and{' '}
              <span className="text-foreground font-medium">ad videos</span> for brands
              and individuals that want to stand out on social media. Working with agencies and brands,
              I've helped create content that has generated{' '}
              <span className="text-foreground font-medium">millions of views</span> across platforms.
              From Instagram Reels to YouTube Shorts, I turn raw footage into scroll-stopping content.
            </motion.p>

            <motion.div variants={textVariants}>
              <motion.a
                href="#portfolio"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
                className="group inline-flex items-center gap-3 px-8 py-4 bg-foreground text-background rounded-full font-semibold text-lg hover:opacity-90 transition-all"
              >
                SEE PROJECTS
                <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
              </motion.a>
            </motion.div>
          </motion.div>
        </div>
      </div>
    </section>
  );
}
